VALUES
  ('dietitian-moex-11564', 'dietitian', 'dietitian-moex-092-cd594556', 'sub-dietitian-03', NULL, 'single_choice', '“魚肝油為兒童期之兒童常攝取的營養補充劑，但攝取過多時可能會造成： 生長快速  腎臟鈣化  體重過重  骨骼強健', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:59+00:00", "source_pdf_sha1": "ca9fc39975a0", "answer_pdf_sha1": "a521d2b7b7b6", "source_family": "moex-gov-tw", "moex": {"exam_code": "092170", "c": "111", "s": "2001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "營養學", "year": "092", "exam_name": "092年第二次醫事人員、中醫師、營養師、獸醫人員、心理師、呼吸治療師考試", "original_question_number": 40, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-11565', 'dietitian', 'dietitian-moex-092-629fe76c', 'sub-dietitian-04', NULL, 'single_choice', '下列關於味覺接受器細胞 (taste receptor cell) 的敘述，何者正確？ 味覺接受器細胞是一種神經元 食物引起的感覺刺激會使味覺接受器細胞產生動作電位 (action potential) 味覺接受器細胞被食物刺激後，產生去極化 (depolarization)，並且釋放化學傳遞物質 甜味與苦味的食物經由相同的分子機轉興奮味覺接受器細胞', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:59+00:00", "source_pdf_sha1": "bcdc485a920f", "answer_pdf_sha1": "03a562c0665c", "source_family": "moex-gov-tw", "moex": {"exam_code": "092170", "c": "111", "s": "1001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "生理學與生物化學", "year": "092", "exam_name": "092年第二次醫事人員、中醫師、營養師、獸醫人員、心理師、呼吸治療師考試", "original_question_number": 1, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-11566', 'dietitian', 'dietitian-moex-092-629fe76c', 'sub-dietitian-04', NULL, 'single_choice', '下列何種症狀不會出現在腎上腺功能過高的患者身上？ 月亮臉    體毛增加，甚至臉上也會出現 低血壓    水腫', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:59+00:00", "source_pdf_sha1": "bcdc485a920f", "answer_pdf_sha1": "03a562c0665c", "source_family": "moex-gov-tw", "moex": {"exam_code": "092170", "c": "111", "s": "1001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "生理學與生物化學", "year": "092", "exam_name": "092年第二次醫事人員、中醫師、營養師、獸醫人員、心理師、呼吸治療師考試", "original_question_number": 2, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-11567', 'dietitian', 'dietitian-moex-092-629fe76c', 'sub-dietitian-04', NULL, 'single_choice', '下列體感覺 (somatic senses) 中，何者的感覺接受器不是游離的神經末梢？ 觸覺  冷覺  暖覺  痛覺', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:59+00:00", "source_pdf_sha1": "bcdc485a920f", "answer_pdf_sha1": "03a562c0665c", "source_family": "moex-gov-tw", "moex": {"exam_code": "092170", "c": "111", "s": "1001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "生理學與生物化學", "year": "092", "exam_name": "092年第二次醫事人員、中醫師、營養師、獸醫人員、心理師、呼吸治療師考試", "original_question_number": 3, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-11568', 'dietitian', 'dietitian-moex-092-629fe76c', 'sub-dietitian-04', NULL, 'single_choice', '下列有關腦電波之敘述，何者不正確？ 在枕葉紀錄到之腦電波，睜眼時之幅度比閉目時低 可用來診斷癲癇症 (epilepsy)，相當有用 按照頻率高至低可分α-波、β-波、δ-波、θ-波四種波段 死亡者無腦電波', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:59+00:00", "source_pdf_sha1": "bcdc485a920f", "answer_pdf_sha1": "03a562c0665c", "source_family": "moex-gov-tw", "moex": {"exam_code": "092170", "c": "111", "s": "1001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "生理學與生物化學", "year": "092", "exam_name": "092年第二次醫事人員、中醫師、營養師、獸醫人員、心理師、呼吸治療師考試", "original_question_number": 4, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-11569', 'dietitian', 'dietitian-moex-092-629fe76c', 'sub-dietitian-04', NULL, 'single_choice', '血小板在活化時會釋放Thromboxane A，而導致下列何種反應的發生？ 2 血管擴張  凝血因子活化  血管收縮  溶解血塊', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:59+00:00", "source_pdf_sha1": "bcdc485a920f", "answer_pdf_sha1": "03a562c0665c", "source_family": "moex-gov-tw", "moex": {"exam_code": "092170", "c": "111", "s": "1001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "生理學與生物化學", "year": "092", "exam_name": "092年第二次醫事人員、中醫師、營養師、獸醫人員、心理師、呼吸治療師考試", "original_question_number": 5, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-11570', 'dietitian', 'dietitian-moex-092-629fe76c', 'sub-dietitian-04', NULL, 'single_choice', '下列何者是舌下唾液腺 (sublingual salivary gland) 所分泌的主要消化酵素？ 澱粉  (amylase)  蛋白分解  (protease)  核糖核酸  (ribonuclease)  胜  (peptidase)', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:59+00:00", "source_pdf_sha1": "bcdc485a920f", "answer_pdf_sha1": "03a562c0665c", "source_family": "moex-gov-tw", "moex": {"exam_code": "092170", "c": "111", "s": "1001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "生理學與生物化學", "year": "092", "exam_name": "092年第二次醫事人員、中醫師、營養師、獸醫人員、心理師、呼吸治療師考試", "original_question_number": 6, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-11571', 'dietitian', 'dietitian-moex-092-629fe76c', 'sub-dietitian-04', NULL, 'single_choice', '下列有關抗利尿素 (ADH) 的敘述，何者正確？ 抗利尿素作用於腎小球 (glomerulus) 以增加水分的重吸收 (reabsorption) 血漿容積 (plasma volume) 降低則經由滲透壓受體 (osmoreceptor) 促使抗利尿素分泌 飲水過多會經由滲透壓受體抑制抗利尿素分泌 飲水過多會經由感壓受體 (baroreceptor) 以增加抗利尿素分泌', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:59+00:00", "source_pdf_sha1": "bcdc485a920f", "answer_pdf_sha1": "03a562c0665c", "source_family": "moex-gov-tw", "moex": {"exam_code": "092170", "c": "111", "s": "1001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "生理學與生物化學", "year": "092", "exam_name": "092年第二次醫事人員、中醫師、營養師、獸醫人員、心理師、呼吸治療師考試", "original_question_number": 7, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-11572', 'dietitian', 'dietitian-moex-092-629fe76c', 'sub-dietitian-04', NULL, 'single_choice', '鈉離子在腎臟重吸收 (reabsorption) 最多的位置在： 鮑氏囊 (Bowman’s capsule)   近曲小管 (proximal tubule) 遠曲小管 (distal tubule)    集尿管 (collecting ducts)', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:59+00:00", "source_pdf_sha1": "bcdc485a920f", "answer_pdf_sha1": "03a562c0665c", "source_family": "moex-gov-tw", "moex": {"exam_code": "092170", "c": "111", "s": "1001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "生理學與生物化學", "year": "092", "exam_name": "092年第二次醫事人員、中醫師、營養師、獸醫人員、心理師、呼吸治療師考試", "original_question_number": 8, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-11573', 'dietitian', 'dietitian-moex-092-629fe76c', 'sub-dietitian-04', NULL, 'single_choice', '下列消化酵素中，何者不是由胰臟細胞分泌？ 脂解  (lipase)    羧基端胜  (carboxypeptidase) 胺基端胜  (aminopeptidase)  澱粉  (amylase)', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:59+00:00", "source_pdf_sha1": "bcdc485a920f", "answer_pdf_sha1": "03a562c0665c", "source_family": "moex-gov-tw", "moex": {"exam_code": "092170", "c": "111", "s": "1001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "生理學與生物化學", "year": "092", "exam_name": "092年第二次醫事人員、中醫師、營養師、獸醫人員、心理師、呼吸治療師考試", "original_question_number": 9, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL)
